package problems;

import java.util.Arrays;
import java.util.HashMap;
import java.util.Map;

public class twoSum {

    public static void main(String[] args) {

        int[] nums = {1, 4, 2, 5, 9};
        int target = 6;

        System.out.println("Two Sum Index values " + Arrays.toString(twosumIndex(nums, target)));
        System.out.println("Two Sum Index values " + Arrays.toString(twosumIndex2(nums, target)));

    }

    public static int[] twosumIndex(int[] nums, int target) {
        // Given an array of integers nums and an integer target, return indices of the two numbers such that 
        // they add up to target.
        // You may assume that each input would have exactly one solution, and you may not use the same element twice.
        // You can return the answer in any order.
        // Example 1:
        // Input: nums = [2,7,11,15], target = 9
        // Output: [0,1]
        // Explanation: Because nums[®] + nums [1] == 9, we
        // return ［O, 1］.

        Map<Integer, Integer> map = new HashMap<>();
        for (int i = 0; i < nums.length; i++) {
            int diff = target - nums[i];
            if (map.containsKey(diff)) {
                return new int[]{map.get(diff), i};
            }
            map.put(nums[i], i);
        }
        return null;
    }

    public static int[] twosumIndex2(int[] numbers, int target) {
        // Given a 1-indexed array of integers numbers that is already sorted in non-decreasing order, find two numbers 
        // such that they add up to a specific target number. Let these two numbers be numbers (index, ) and numbers(indexz] 
        // where 1 <= index, < index ‹= numbers.length.
        // Return the indices of the two numbers, index, and index, added by one as an integer array (index,, indexz] of length 2.
        // The tests are generated such that there is exactly one solution. You may not use the same element twice.
        // Your solution must use only constant extra space.
        // Example 1:
        // Input: numbers = [2,Z,11,15], target = 9
        // Output: [1,2]
        // Explanation: The sum of 2 and 7 is 9. Therefore, index, = 1, index = 2. We return [1,2]

        int left = 0;
        int right = numbers.length - 1;
        while (left < right) {
            if (numbers[left] + numbers[right] < target) {
                left++;
            } else if (numbers[left] + numbers[right] > target) {
                right--;
            } else {
                return new int[]{left + 1, right + 1};
            }
        }
        return null;

    }
  }
